from __future__ import annotations
import json
from pathlib import Path
HTML=Path('docs/index.html');DATA=Path('data/dashboard/wnba_alt_streak_performance.json')
CSS=r'''<style id="v4-alt-performance-style">.altPerfGrid{display:grid;grid-template-columns:repeat(auto-fit,minmax(160px,1fr));gap:10px;margin:14px 0}.altPerfCard{border:1px solid #20304b;border-radius:14px;padding:14px;background:#0a1423}.altPerfCard b{font-size:22px}.altPerfTableWrap{overflow:auto;border:1px solid #1e2a43;border-radius:16px;margin-top:14px}.altPerfTable{min-width:760px}.altPerfPos{color:#00e39b;font-weight:900}.altPerfNeg{color:#ff4d67;font-weight:900}.altPerfMid{color:#ffd166;font-weight:900}.altPerfNote{color:#7e8ba3;font-size:11px;margin-top:10px}</style>'''
SCRIPT=r'''<script id="v4-alt-performance-script">(function(){const esc=v=>typeof E==='function'?E(v):String(v??'');const arr=v=>Array.isArray(v)?v:[];const val=(v,d='—')=>v===undefined||v===null||v===''?d:v;const pct=v=>v===undefined||v===null?'—':(Number(v)*100).toFixed(1)+'%';const units=v=>v===undefined||v===null?'—':(Number(v)>=0?'+':'')+Number(v).toFixed(2)+'u';const cls=v=>v===undefined||v===null?'altPerfMid':Number(v)>0?'altPerfPos':Number(v)<0?'altPerfNeg':'altPerfMid';function table(title,rows,labelField){const body=arr(rows).map(r=>`<tr><td><b>${esc(val(r[labelField]))}</b></td><td>${esc(val(r.graded,0))}</td><td>${esc(val(r.wins,0))}-${esc(val(r.losses,0))}-${esc(val(r.pushes,0))}</td><td>${esc(pct(r.win_rate))}</td><td class="${cls(r.roi)}">${esc(pct(r.roi))}</td><td class="${cls(r.profit_loss_units)}">${esc(units(r.profit_loss_units))}</td></tr>`).join('');return `<div class="altPerfTableWrap"><table class="altPerfTable"><thead><tr><th>${esc(title)}</th><th>Graded</th><th>W-L-P</th><th>Win Rate</th><th>ROI</th><th>P/L</th></tr></thead><tbody>${body||'<tr><td colspan="6">No graded data yet.</td></tr>'}</tbody></table></div>`}window.altPerformance=function(){const p=DATA.alt_performance||{},s=p.summary||{};return `<div class="section"><div class="row"><div><h2 class="mono">ALT Performance</h2><div class="small mono">Frozen pregame snapshots graded against verified player game logs.</div></div></div><div class="altPerfGrid"><div class="altPerfCard"><div class="small">Snapshots</div><b>${esc(val(s.snapshots,0))}</b></div><div class="altPerfCard"><div class="small">Graded</div><b>${esc(val(s.graded,0))}</b></div><div class="altPerfCard"><div class="small">Record</div><b>${esc(val(s.wins,0))}-${esc(val(s.losses,0))}-${esc(val(s.pushes,0))}</b></div><div class="altPerfCard"><div class="small">Win Rate</div><b>${esc(pct(s.win_rate))}</b></div><div class="altPerfCard"><div class="small">ROI</div><b class="${cls(s.roi)}">${esc(pct(s.roi))}</b></div><div class="altPerfCard"><div class="small">Profit/Loss</div><b class="${cls(s.profit_loss_units)}">${esc(units(s.profit_loss_units))}</b></div><div class="altPerfCard"><div class="small">Pending</div><b>${esc(val(s.pending,0))}</b></div><div class="altPerfCard"><div class="small">Recommended Threshold</div><b>${esc(val(s.recommended_threshold,'Collecting data'))}</b></div></div>${table('Score Band',p.by_score_band,'score_band')}${table('Grade',p.by_grade,'streak_grade')}${table('Action',p.by_action,'streak_action')}${table('Stat',p.by_stat,'stat')}${table('Side',p.by_side,'side')}${table('Sportsbook',p.by_sportsbook,'sportsbook')}${table('Matchup Source',p.by_matchup_source,'opponent_rank_source')}<div class="altPerfNote mono">Flat 1-unit tracking. CLV stays blank until a verified closing-line snapshot exists. Recommended thresholds require at least 20 graded plays in a profitable band.</div></div>`};const oldRender=window.render;window.render=function(view){if(view==='altperf'){document.querySelectorAll('.tab').forEach(b=>b.classList.toggle('a',b.dataset.view==='altperf'));const root=document.getElementById('root');if(root)root.innerHTML=window.altPerformance();return}return oldRender(view)};function addTab(){const tabs=document.getElementById('tabs');if(!tabs||tabs.querySelector('[data-view="altperf"]'))return;const button=document.createElement('button');button.className='tab';button.dataset.view='altperf';button.textContent='ALT Performance';button.onclick=()=>window.render('altperf');const alt=tabs.querySelector('[data-view="alt"]');if(alt&&alt.nextSibling)tabs.insertBefore(button,alt.nextSibling);else tabs.appendChild(button)}addTab()})();</script>'''
def replace_block(html,start_marker,end_marker,replacement):
    s=html.find(start_marker)
    if s<0:return html
    e=html.find(end_marker,s)
    if e<0:return html
    return html[:s]+replacement.strip()+html[e+len(end_marker):]
def main():
    if not HTML.exists():raise SystemExit('docs/index.html missing')
    try:payload=json.load(DATA.open(encoding='utf-8')) if DATA.exists() else {}
    except Exception:payload={}
    html=HTML.read_text(encoding='utf-8');data=f'<script id="v4-alt-performance-data">DATA.alt_performance={json.dumps(payload,separators=(",",":"),ensure_ascii=False)};</script>'
    html=replace_block(html,'<script id="v4-alt-performance-data">','</script>',data) if 'id="v4-alt-performance-data"' in html else html.replace('</body>',data+'</body>')
    html=replace_block(html,'<style id="v4-alt-performance-style">','</style>',CSS) if 'id="v4-alt-performance-style"' in html else html.replace('</head>',CSS+'</head>')
    html=replace_block(html,'<script id="v4-alt-performance-script">','</script>',SCRIPT) if 'id="v4-alt-performance-script"' in html else html.replace('</body>',SCRIPT+'</body>')
    HTML.write_text(html,encoding='utf-8');print('ALT Performance tab applied')
if __name__=='__main__':main()
